package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setUp() {
        csvFormat = new CSVFormat(',', '\"', null, null, null, false, true, "\r\n", null, null, false, false);
    }

    @Test
    public void testToString() {
        String expected = "Delimiter=<,> Escape=<\"> QuoteChar=<\"> RecordSeparator=<\r\n> EmptyLines:ignored SkipHeaderRecord:false";
        String result = csvFormat.toString();
        assertEquals(expected, result);
    }

    // Add more test cases for other methods if needed

}
